    66→          mb="quark"
    67→        />
    68→        <LineSeparator />
    69→      </Box>
    70→    );
    71→  }
    72→
    73→  return (
    74→    <>
    75→      <ScrollView>
    76→        <Box flex={1} justify="space-between">
    77→          <Box width="100%">
    78→            {isAdditionalCardFlowEnabled && showLimitMessageAtTop()}
    79→            {physicalCard?.length > 0 ? (
    80→              <FlatList
    81→                keyExtractor={(item) => String(item?.id)}
    82→                data={physicalCard}
    83→                ItemSeparatorComponent={lineSeparator}
